function rememberUser(username, passwordHash) {
    var expiry = new Date();
    expiry.setTime(expiry.getTime() + (30 * 24 * 60 * 60 * 1000)); // 30 days in milliseconds

    document.cookie = "username=" + username + ";expires=" + expiry.toUTCString();
    document.cookie = "password_hash=" + passwordHash + ";expires=" + expiry.toUTCString();
}

function checkRememberMe() {
    var cookies = document.cookie.split(';');

    for (var i = 0; i < cookies.length; i++) {
        var cookie = cookies[i].trim();
        if (cookie.startsWith("username=")) {
            var username = cookie.substring(8);
        } else if (cookie.startsWith("password_hash=")) {
            var passwordHash = cookie.substring(15);
        }
    }

    if (username && passwordHash) {
        autoLogin(username, passwordHash);
    }
}

